insert into public.master_categories (module, code, name_th, unit, color_hex, pattern, sort_order, active, metadata)
select module, code, name_th, unit, color_hex, 'solid', sort_order, true, jsonb_build_object('source', 'Hygiene.xlsx CSV import')
from rows
on conflict (module, code) do update
set name_th = excluded.name_th,
    unit = excluded.unit,
    active = true,
    metadata = public.master_categories.metadata || excluded.metadata,
    updated_at = now();

