insert into public.daily_entries (category_id, entry_date, quantity, note)
select mc.id, rows.entry_date, rows.quantity, rows.note
from rows
join public.master_categories mc
  on mc.module = rows.module
 and lower(trim(mc.name_th)) = lower(trim(rows.category_name))
on conflict (category_id, entry_date) do update
set quantity = excluded.quantity,
    note = excluded.note,
    updated_at = now();

