insert into public.scrap_sales (sale_date, category_id, weight_kg, price_per_kg, note)
select rows.sale_date, mc.id, rows.weight_kg, rows.price_per_kg, rows.note
from rows
join public.master_categories mc
  on mc.module = 'scrap_material'
 and lower(trim(mc.name_th)) = lower(trim(rows.category_name));

-- 5) Store monthly-only source data in a staging/reference table (not daily_entries)
create table if not exists public.hygiene_monthly_entries_source (
  id uuid primary key default gen_random_uuid(),
  module text not null,
  category_name text not null,
  month_start date not null,
  month_end date not null,
  quantity numeric(18,4) not null,
  unit text not null,
  source_sheet text,
  source_month text,
  note text,
  imported_at timestamptz not null default now(),
  constraint hygiene_monthly_entries_unique unique (module, category_name, month_start)
);

