insert into public.hygiene_monthly_entries_source (module, category_name, month_start, month_end, quantity, unit, source_sheet, source_month, note)
select module, category_name, month_start, month_end, quantity, unit, source_sheet, source_month, note
from rows
on conflict (module, category_name, month_start) do update
set month_end = excluded.month_end,
    quantity = excluded.quantity,
    unit = excluded.unit,
    source_sheet = excluded.source_sheet,
    source_month = excluded.source_month,
    note = excluded.note,
    imported_at = now();

-- 6) Quick summary
select 'master_categories_hygiene' as dataset, count(*) as rows
from public.master_categories
where metadata->>'source' = 'Hygiene.xlsx CSV import'
union all
select 'daily_entries_imported_range', count(*)
from public.daily_entries de
join public.master_categories mc on mc.id = de.category_id
where de.entry_date between date '2025-11-01' and date '2026-05-31'
  and mc.module in ('waste','tissue','animal_feed','garbage_bag','consumable')
union all
select 'scrap_sales_hygiene', count(*)
from public.scrap_sales
where note ilike '%Hygiene%'
union all
select 'hygiene_monthly_entries_source', count(*)
from public.hygiene_monthly_entries_source;

commit;
